import React, { useState, useEffect, useRef, useCallback } from 'react';
import './App.css';

// ─── Agent Config ───────────────────────────────────────────────────────────

const AGENTS_CONFIG = {
  logique:      { name: "Agent Logique",      emoji: "🔷", color: "#3B82F6", role: "Analyste Rationnel",    initials: "L" },
  creatif:      { name: "Agent Créatif",      emoji: "✨", color: "#F59E0B", role: "Penseur Innovant",       initials: "C" },
  ethique:      { name: "Agent Éthique",      emoji: "⚖️", color: "#10B981", role: "Gardien Moral",          initials: "É" },
  critique:     { name: "Agent Critique",     emoji: "🔍", color: "#EF4444", role: "Avocat du Diable",       initials: "K" },
  memoire:      { name: "Agent Mémoire",      emoji: "🧩", color: "#8B5CF6", role: "Archiviste Collectif",   initials: "M" },
  scientifique: { name: "Agent Scientifique", emoji: "🔬", color: "#06B6D4", role: "Expert RAG",             initials: "S" },
  mediateur:    { name: "Agent Médiateur",    emoji: "🌐", color: "#F97316", role: "Architecte du Consensus",initials: "Md" },
};

const AGENT_ORDER = ["logique", "creatif", "ethique", "critique", "scientifique", "memoire"];

// ─── Utility ────────────────────────────────────────────────────────────────

const delay = (ms) => new Promise(r => setTimeout(r, ms));

// ─── Network Graph Component ─────────────────────────────────────────────────

function NetworkGraph({ agents, alliances, conflicts, activeAgent, agentStatuses }) {
  const canvasRef = useRef(null);
  const animRef = useRef(null);
  const timeRef = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const W = canvas.width = canvas.offsetWidth;
    const H = canvas.height = canvas.offsetHeight;
    const cx = W / 2, cy = H / 2;
    const r = Math.min(W, H) * 0.35;

    const agentIds = Object.keys(AGENTS_CONFIG);
    const positions = {};
    agentIds.forEach((id, i) => {
      const angle = (i / agentIds.length) * 2 * Math.PI - Math.PI / 2;
      positions[id] = { x: cx + r * Math.cos(angle), y: cy + r * Math.sin(angle) };
    });

    function draw(t) {
      ctx.clearRect(0, 0, W, H);

      // Background grid
      ctx.strokeStyle = 'rgba(99,102,241,0.06)';
      ctx.lineWidth = 1;
      for (let x = 0; x < W; x += 40) { ctx.beginPath(); ctx.moveTo(x,0); ctx.lineTo(x,H); ctx.stroke(); }
      for (let y = 0; y < H; y += 40) { ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(W,y); ctx.stroke(); }

      // Center hub
      const hubGrad = ctx.createRadialGradient(cx, cy, 0, cx, cy, 28);
      hubGrad.addColorStop(0, 'rgba(99,102,241,0.8)');
      hubGrad.addColorStop(1, 'rgba(99,102,241,0)');
      ctx.fillStyle = hubGrad;
      ctx.beginPath(); ctx.arc(cx, cy, 28, 0, 2 * Math.PI); ctx.fill();

      ctx.fillStyle = 'rgba(255,255,255,0.9)';
      ctx.font = 'bold 10px monospace';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('CORE', cx, cy);

      // Alliance lines (green, animated)
      alliances.forEach(({ agent1, agent2 }) => {
        const p1 = positions[agent1], p2 = positions[agent2];
        if (!p1 || !p2) return;
        const prog = (Math.sin(t * 0.002) + 1) / 2;
        ctx.strokeStyle = `rgba(16,185,129,${0.2 + prog * 0.5})`;
        ctx.lineWidth = 1.5;
        ctx.setLineDash([6, 4]);
        ctx.beginPath(); ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.stroke();
        ctx.setLineDash([]);
      });

      // Conflict lines (red)
      conflicts.forEach(({ agent1, agent2 }) => {
        const p1 = positions[agent1], p2 = positions[agent2];
        if (!p1 || !p2) return;
        ctx.strokeStyle = 'rgba(239,68,68,0.35)';
        ctx.lineWidth = 1;
        ctx.setLineDash([3, 6]);
        ctx.beginPath(); ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.stroke();
        ctx.setLineDash([]);
      });

      // Connection to core
      agentIds.forEach(id => {
        const p = positions[id];
        const isActive = activeAgent === id;
        const opacity = isActive ? 0.5 : 0.12;
        ctx.strokeStyle = `rgba(99,102,241,${opacity})`;
        ctx.lineWidth = isActive ? 1.5 : 0.5;
        ctx.beginPath(); ctx.moveTo(cx, cy); ctx.lineTo(p.x, p.y); ctx.stroke();
      });

      // Agent nodes
      agentIds.forEach(id => {
        const p = positions[id];
        const cfg = AGENTS_CONFIG[id];
        const isActive = activeAgent === id;
        const status = agentStatuses[id] || 'idle';
        const nodeR = isActive ? 22 : 16;

        // Pulse for active agent
        if (isActive) {
          const pulse = (Math.sin(t * 0.006) + 1) / 2;
          const pulseGrad = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, 40);
          pulseGrad.addColorStop(0, cfg.color + '60');
          pulseGrad.addColorStop(1, 'transparent');
          ctx.fillStyle = pulseGrad;
          ctx.beginPath(); ctx.arc(p.x, p.y, 40 + pulse * 10, 0, 2 * Math.PI); ctx.fill();
        }

        // Node circle
        const grad = ctx.createRadialGradient(p.x - nodeR*0.3, p.y - nodeR*0.3, 0, p.x, p.y, nodeR);
        grad.addColorStop(0, cfg.color + 'ff');
        grad.addColorStop(1, cfg.color + '99');
        ctx.fillStyle = grad;
        ctx.beginPath(); ctx.arc(p.x, p.y, nodeR, 0, 2 * Math.PI); ctx.fill();

        // Border
        ctx.strokeStyle = isActive ? '#ffffff' : cfg.color + '88';
        ctx.lineWidth = isActive ? 2 : 1;
        ctx.stroke();

        // Emoji
        ctx.font = `${isActive ? 14 : 11}px serif`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillStyle = '#fff';
        ctx.fillText(cfg.emoji, p.x, p.y);

        // Name label
        ctx.font = `${isActive ? '600' : '400'} 9px monospace`;
        ctx.fillStyle = isActive ? cfg.color : 'rgba(200,200,220,0.7)';
        ctx.fillText(cfg.name.replace('Agent ', ''), p.x, p.y + nodeR + 12);
      });
    }

    function animate(t) {
      timeRef.current = t;
      draw(t);
      animRef.current = requestAnimationFrame(animate);
    }
    animRef.current = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(animRef.current);
  }, [alliances, conflicts, activeAgent, agentStatuses]);

  return (
    <canvas
      ref={canvasRef}
      style={{ width: '100%', height: '100%', display: 'block' }}
    />
  );
}

// ─── Agent Message Card ───────────────────────────────────────────────────────

function AgentCard({ message, isNew }) {
  const cfg = AGENTS_CONFIG[message.agent_id];
  if (!cfg) return null;
  return (
    <div className={`agent-card ${isNew ? 'agent-card--new' : ''}`} style={{ '--agent-color': cfg.color }}>
      <div className="agent-card__header">
        <div className="agent-card__avatar" style={{ background: cfg.color }}>
          {cfg.emoji}
        </div>
        <div className="agent-card__meta">
          <span className="agent-card__name">{cfg.name}</span>
          <span className="agent-card__role">{cfg.role}</span>
        </div>
        <div className="agent-card__round">R{message.round}</div>
      </div>
      <div className="agent-card__content">{message.content}</div>
    </div>
  );
}

// ─── Consensus Panel ─────────────────────────────────────────────────────────

function ConsensusPanel({ consensus, votes, consensusScore, onValidate, onReject }) {
  const [comment, setComment] = useState('');
  const approved = Object.values(votes || {}).filter(v => v === 'approve').length;
  const abstained = Object.values(votes || {}).filter(v => v === 'abstain').length;

  return (
    <div className="consensus-panel">
      <div className="consensus-panel__header">
        <span className="consensus-panel__icon">🌐</span>
        <h3>CONSENSUS COLLECTIF</h3>
        <div className="consensus-panel__score">
          <div className="score-bar">
            <div className="score-bar__fill" style={{ width: `${consensusScore * 100}%` }} />
          </div>
          <span>{Math.round(consensusScore * 100)}%</span>
        </div>
      </div>

      <div className="consensus-panel__votes">
        {Object.entries(votes || {}).map(([agentId, vote]) => {
          const cfg = AGENTS_CONFIG[agentId];
          if (!cfg) return null;
          return (
            <div key={agentId} className={`vote-chip vote-chip--${vote}`}>
              <span>{cfg.emoji}</span>
              <span className="vote-chip__label">{vote === 'approve' ? '✓' : vote === 'abstain' ? '~' : '✗'}</span>
            </div>
          );
        })}
      </div>

      <div className="consensus-panel__vote-summary">
        {approved} approuvent · {abstained} s'abstiennent
      </div>

      <div className="consensus-panel__text">
        {consensus}
      </div>

      <div className="consensus-panel__human">
        <div className="human-badge">👤 VALIDATION HUMAINE REQUISE</div>
        <textarea
          className="human-comment"
          placeholder="Commentaire optionnel..."
          value={comment}
          onChange={e => setComment(e.target.value)}
        />
        <div className="human-actions">
          <button className="btn btn--approve" onClick={() => onValidate(comment)}>
            ✓ VALIDER
          </button>
          <button className="btn btn--reject" onClick={() => onReject(comment)}>
            ✗ REJETER
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Status Bar ───────────────────────────────────────────────────────────────

function StatusBar({ status, round, maxRounds, activeAgent, ragReady }) {
  const cfg = activeAgent ? AGENTS_CONFIG[activeAgent] : null;
  return (
    <div className="status-bar">
      <div className="status-bar__indicator" data-status={status} />
      <span className="status-bar__text">
        {status === 'idle' && 'EN ATTENTE DE QUESTION'}
        {status === 'rag' && '📚 Récupération documentaire...'}
        {status === 'debating' && cfg && `${cfg.emoji} ${cfg.name} délibère... · Round ${round}/${maxRounds}`}
        {status === 'consensus' && '🌐 Génération du consensus...'}
        {status === 'complete' && '✓ Débat terminé · Validation humaine requise'}
        {status === 'validated' && '✅ Consensus validé'}
        {status === 'rejected' && '❌ Consensus rejeté'}
      </span>
      {ragReady && <span className="status-bar__rag">RAG ✓</span>}
    </div>
  );
}

// ─── Main App ────────────────────────────────────────────────────────────────

const API_BASE = process.env.REACT_APP_API_URL || 'http://localhost:8000';

export default function App() {
  const [question, setQuestion] = useState('');
  const [maxRounds, setMaxRounds] = useState(2);
  const [useRag, setUseRag] = useState(true);
  const [status, setStatus] = useState('idle');
  const [messages, setMessages] = useState([]);
  const [activeAgent, setActiveAgent] = useState(null);
  const [agentStatuses, setAgentStatuses] = useState({});
  const [alliances, setAlliances] = useState([]);
  const [conflicts, setConflicts] = useState([]);
  const [consensus, setConsensus] = useState(null);
  const [consensusScore, setConsensusScore] = useState(0);
  const [votes, setVotes] = useState({});
  const [debateId, setDebateId] = useState(null);
  const [ragReady, setRagReady] = useState(false);
  const [round, setRound] = useState(0);
  const [systemLog, setSystemLog] = useState([]);
  const [validationResult, setValidationResult] = useState(null);
  const [newMessageId, setNewMessageId] = useState(null);

  const messagesEndRef = useRef(null);
  const abortRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addLog = useCallback((msg) => {
    setSystemLog(prev => [...prev.slice(-30), { msg, ts: Date.now() }]);
  }, []);

  const startDebate = useCallback(async () => {
    if (!question.trim() || status === 'debating' || status === 'consensus') return;

    // Reset
    setMessages([]);
    setAlliances([]);
    setConflicts([]);
    setConsensus(null);
    setConsensusScore(0);
    setVotes({});
    setDebateId(null);
    setRagReady(false);
    setRound(0);
    setSystemLog([]);
    setValidationResult(null);
    setActiveAgent(null);
    setAgentStatuses({});
    setStatus('debating');
    addLog('Initialisation du débat collectif...');

    try {
      const response = await fetch(`${API_BASE}/debate/stream`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ question, max_rounds: maxRounds, use_rag: useRag })
      });

      if (!response.ok) throw new Error(`HTTP ${response.status}`);

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let buffer = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;
          try {
            const event = JSON.parse(line.slice(6));
            handleEvent(event);
          } catch (e) {
            // skip malformed
          }
        }
      }
    } catch (err) {
      addLog(`Erreur: ${err.message}`);
      setStatus('idle');
    }
  }, [question, maxRounds, useRag, status, addLog]);

  const handleEvent = useCallback((event) => {
    switch (event.type) {
      case 'rag_ready':
        setRagReady(true);
        setStatus('rag');
        addLog(`📚 RAG: ${event.context_preview}`);
        break;

      case 'debate_start':
        setDebateId(event.debate_id);
        setStatus('debating');
        addLog(`🚀 Débat lancé: ${event.debate_id.slice(0,8)}...`);
        break;

      case 'round_start':
        setRound(event.round);
        addLog(`🔄 Round ${event.round}/${event.max_rounds}`);
        break;

      case 'agent_thinking':
        setActiveAgent(event.agent_id);
        setAgentStatuses(prev => ({ ...prev, [event.agent_id]: 'thinking' }));
        addLog(`${AGENTS_CONFIG[event.agent_id]?.emoji} ${event.agent_name} réfléchit...`);
        break;

      case 'agent_response':
        setActiveAgent(null);
        setAgentStatuses(prev => ({ ...prev, [event.agent_id]: 'done' }));
        const msgId = `${event.agent_id}-${event.round}-${Date.now()}`;
        setNewMessageId(msgId);
        setMessages(prev => [...prev, { ...event, _id: msgId }]);
        if (event.alliances) setAlliances(event.alliances);
        if (event.conflicts) setConflicts(event.conflicts);
        addLog(`✅ ${event.agent_name} a répondu`);
        break;

      case 'round_end':
        setConsensusScore(event.consensus_score || 0);
        break;

      case 'consensus_start':
        setStatus('consensus');
        setActiveAgent('mediateur');
        addLog('🌐 Génération du consensus...');
        break;

      case 'consensus_ready':
        setActiveAgent(null);
        setConsensus(event.consensus);
        setConsensusScore(event.consensus_score || 0.82);
        setVotes(event.votes || {});
        setAlliances(event.alliances || []);
        setConflicts(event.conflicts || []);
        addLog('✨ Consensus généré');
        break;

      case 'debate_complete':
        setStatus('complete');
        addLog('✓ Débat complet. Validation humaine requise.');
        break;

      case 'stream_end':
        if (status !== 'complete') setStatus('complete');
        break;

      default:
        break;
    }
  }, [status, addLog]);

  const handleValidate = useCallback(async (comment) => {
    if (!debateId) return;
    try {
      const res = await fetch(`${API_BASE}/debate/validate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          debate_id: debateId,
          decision: 'approve',
          comment
        })
      });
      const data = await res.json();
      setValidationResult(data);
      setStatus('validated');
      addLog('✅ Consensus validé par humain');
    } catch (e) {
      addLog(`Erreur validation: ${e.message}`);
    }
  }, [debateId, addLog]);

  const handleReject = useCallback(async (comment) => {
    if (!debateId) return;
    try {
      const res = await fetch(`${API_BASE}/debate/validate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          debate_id: debateId,
          decision: 'reject',
          comment
        })
      });
      const data = await res.json();
      setValidationResult(data);
      setStatus('rejected');
      addLog('❌ Consensus rejeté par humain');
    } catch (e) {
      addLog(`Erreur: ${e.message}`);
    }
  }, [debateId, addLog]);

  const isRunning = status === 'debating' || status === 'consensus' || status === 'rag';

  const EXAMPLE_QUESTIONS = [
    "Faut-il remplacer certains emplois par l'IA ?",
    "Comment réduire le chômage grâce à l'IA ?",
    "L'IA générative menace-t-elle la créativité humaine ?",
    "Comment rendre l'IA plus éthique et transparente ?"
  ];

  return (
    <div className="app">
      {/* Header */}
      <header className="app-header">
        <div className="app-header__logo">
          <span className="logo-icon">🧠</span>
          <div>
            <div className="logo-title">COLLECTIVE MIND</div>
            <div className="logo-sub">Système d'Intelligence Émergente Multi-Agent</div>
          </div>
        </div>
        <div className="app-header__stats">
          <div className="stat">
            <span className="stat__val">{Object.keys(AGENTS_CONFIG).length}</span>
            <span className="stat__label">AGENTS</span>
          </div>
          <div className="stat">
            <span className="stat__val">{messages.length}</span>
            <span className="stat__label">MSGS</span>
          </div>
          <div className="stat">
            <span className="stat__val">{alliances.length}</span>
            <span className="stat__label">ALLIANCES</span>
          </div>
          <div className="stat">
            <span className="stat__val">{Math.round(consensusScore * 100)}%</span>
            <span className="stat__label">CONSENSUS</span>
          </div>
        </div>
      </header>

      <StatusBar
        status={status}
        round={round}
        maxRounds={maxRounds}
        activeAgent={activeAgent}
        ragReady={ragReady}
      />

      <div className="app-body">
        {/* Left Panel: Network + Controls */}
        <aside className="left-panel">
          <div className="network-container">
            <div className="panel-label">RÉSEAU D'AGENTS</div>
            <NetworkGraph
              agents={AGENTS_CONFIG}
              alliances={alliances}
              conflicts={conflicts}
              activeAgent={activeAgent}
              agentStatuses={agentStatuses}
            />
          </div>

          {/* Alliance/Conflict Legend */}
          <div className="relationships">
            {alliances.length > 0 && (
              <div className="rel-section">
                <div className="rel-title rel-title--alliance">🤝 ALLIANCES</div>
                {alliances.map((a, i) => (
                  <div key={i} className="rel-item rel-item--alliance">
                    {AGENTS_CONFIG[a.agent1]?.emoji} ↔ {AGENTS_CONFIG[a.agent2]?.emoji}
                    <span>{a.topic}</span>
                  </div>
                ))}
              </div>
            )}
            {conflicts.length > 0 && (
              <div className="rel-section">
                <div className="rel-title rel-title--conflict">⚡ TENSIONS</div>
                {conflicts.map((c, i) => (
                  <div key={i} className="rel-item rel-item--conflict">
                    {AGENTS_CONFIG[c.agent1]?.emoji} ↕ {AGENTS_CONFIG[c.agent2]?.emoji}
                    <span>{c.topic}</span>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Agent Status Grid */}
          <div className="agent-grid">
            {Object.entries(AGENTS_CONFIG).map(([id, cfg]) => (
              <div
                key={id}
                className={`agent-pip ${activeAgent === id ? 'agent-pip--active' : ''} ${agentStatuses[id] === 'done' ? 'agent-pip--done' : ''}`}
                style={{ '--color': cfg.color }}
                title={`${cfg.name} - ${cfg.role}`}
              >
                <span>{cfg.emoji}</span>
              </div>
            ))}
          </div>
        </aside>

        {/* Center: Debate Feed */}
        <main className="debate-feed">
          <div className="debate-feed__messages">
            {messages.length === 0 && status === 'idle' && (
              <div className="empty-state">
                <div className="empty-state__icon">🧠</div>
                <p>Posez une question complexe pour démarrer le débat collectif.</p>
                <div className="example-questions">
                  {EXAMPLE_QUESTIONS.map((q, i) => (
                    <button
                      key={i}
                      className="example-btn"
                      onClick={() => setQuestion(q)}
                    >
                      {q}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {messages.map((msg, i) => (
              <AgentCard
                key={msg._id || i}
                message={msg}
                isNew={msg._id === newMessageId}
              />
            ))}

            {isRunning && (
              <div className="typing-indicator">
                <div className="typing-dots">
                  <span /><span /><span />
                </div>
                {activeAgent && AGENTS_CONFIG[activeAgent] && (
                  <span className="typing-label">
                    {AGENTS_CONFIG[activeAgent].emoji} {AGENTS_CONFIG[activeAgent].name} réfléchit...
                  </span>
                )}
              </div>
            )}

            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="debate-input">
            <div className="debate-input__controls">
              <label className="control-label">
                Rounds:
                <select
                  value={maxRounds}
                  onChange={e => setMaxRounds(Number(e.target.value))}
                  disabled={isRunning}
                  className="control-select"
                >
                  <option value={1}>1</option>
                  <option value={2}>2</option>
                  <option value={3}>3</option>
                </select>
              </label>
              <label className="control-toggle">
                <input
                  type="checkbox"
                  checked={useRag}
                  onChange={e => setUseRag(e.target.checked)}
                  disabled={isRunning}
                />
                <span>RAG</span>
              </label>
            </div>
            <div className="debate-input__row">
              <textarea
                className="debate-input__textarea"
                value={question}
                onChange={e => setQuestion(e.target.value)}
                placeholder="Posez une question complexe au collectif..."
                disabled={isRunning}
                onKeyDown={e => {
                  if (e.key === 'Enter' && !e.shiftKey && !isRunning) {
                    e.preventDefault();
                    startDebate();
                  }
                }}
              />
              <button
                className={`debate-input__submit ${isRunning ? 'debate-input__submit--loading' : ''}`}
                onClick={startDebate}
                disabled={isRunning || !question.trim()}
              >
                {isRunning ? (
                  <span className="spinner" />
                ) : (
                  '▶'
                )}
              </button>
            </div>
          </div>
        </main>

        {/* Right Panel: Consensus + Logs */}
        <aside className="right-panel">
          {consensus && (status === 'complete' || status === 'consensus' || status === 'validated' || status === 'rejected') && (
            <>
              {!validationResult ? (
                <ConsensusPanel
                  consensus={consensus}
                  votes={votes}
                  consensusScore={consensusScore}
                  onValidate={handleValidate}
                  onReject={handleReject}
                />
              ) : (
                <div className="validation-result">
                  <div className={`validation-result__badge ${validationResult.status === 'validated' ? 'badge--approved' : 'badge--rejected'}`}>
                    {validationResult.status === 'validated' ? '✅ VALIDÉ' : '❌ REJETÉ'}
                  </div>
                  <p className="validation-result__text">{validationResult.final_consensus}</p>
                  {validationResult.comment && (
                    <p className="validation-result__comment">💬 {validationResult.comment}</p>
                  )}
                </div>
              )}
            </>
          )}

          {/* System Log */}
          <div className="system-log">
            <div className="panel-label">JOURNAL SYSTÈME</div>
            <div className="system-log__entries">
              {systemLog.map((entry, i) => (
                <div key={i} className="log-entry">
                  <span className="log-entry__ts">{new Date(entry.ts).toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}</span>
                  <span className="log-entry__msg">{entry.msg}</span>
                </div>
              ))}
              {systemLog.length === 0 && (
                <div className="log-entry log-entry--empty">En attente...</div>
              )}
            </div>
          </div>
        </aside>
      </div>
    </div>
  );
}
